import React from "react";

const Header = ({ user }) => {

  // 🔹 Time-based greeting
  const getGreeting = () => {
    const hour = new Date().getHours();

    if (hour < 12) return "Good morning";
    if (hour < 18) return "Good afternoon";
    return "Good evening";
  };

  return (
    <div className="flex items-center justify-between px-6 py-4 bg-white/10 backdrop-blur-lg border-b border-white/20 rounded-xl">

      {/* 🔹 Left Section */}
      <div>
        <h1 className="text-2xl font-semibold text-white">
          👋 {getGreeting()}, {user ? user.name : "Guest"}
        </h1>
        <p className="text-sm text-white/70 mt-1">
          Be efficient, be productive.
        </p>
      </div>

      {/* 🔹 Right Section */}
      <div className="flex items-center gap-4">

        {/* Profile */}
        {user && (
          <div className="flex items-center gap-3 bg-white/10 px-3 py-2 rounded-lg">
            <img
              src="https://i.pravatar.cc/40"
              alt="profile"
              className="w-9 h-9 rounded-full border border-white/30"
            />
            <span className="text-white text-sm font-medium">
              {user.name}
            </span>
          </div>
        )}

        {/* Login / Logout Button */}
        {user ? (
          <button
            className="px-4 py-2 bg-red-500 hover:bg-red-600 text-white rounded-lg transition"
          >
            Logout
          </button>
        ) : (
          <button
            className="px-4 py-2 bg-white text-black rounded-lg hover:bg-white/90 transition"
          >
            Login
          </button>
        )}

      </div>
    </div>
  );
};

export default Header;
